local function CanBePoisoned(self, gas, ...) if self.inst and self.inst.GetCharacterBonus then local immunity = self.inst:GetCharacterBonus( "poisonimmunity" ) > 0x0 or self.inst:GetCharacterBonus( "sacreddefense" ) > 0x0 if immunity then return false end end return self.dycOldCanBePoisoned(self, gas, ...) end local function DYCPoisonable(self) self.dycOldCanBePoisoned = self.CanBePoisoned self.CanBePoisoned = CanBePoisoned end return DYCPoisonable 